+
+// InitialLoad applies the startup configuration without recording a reload
+// outcome. It establishes the configuration used for future rollbacks.
+func (t *transactionalReloadTracker) InitialLoad(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) (err error) {
+	start := time.Now()
+	logger.Info("Loading configuration file", "filename", filename)
+	defer func() {
+		if err == nil {
+			configSuccess.Set(1)
+			configSuccessTime.SetToCurrentTime()
+			callback(true)
+		} else {
+			configSuccess.Set(0)
+			callback(false)
+		}
+	}()
+
+	conf, err := loadReloadConfig(filename, enableExemplarStorage, logger)
+	if err != nil {
+		return err
+	}
+	failed := false
+	for _, rl := range rls {
+		rstart := time.Now()
+		if err := rl.reloader(conf); err != nil {
+			logger.Error("Failed to apply configuration", "err", err)
+			failed = true
+		}
+		logger = logger.With(rl.name, time.Since(rstart))
+	}
+	if failed {
+		return fmt.Errorf("one or more errors occurred while applying the new configuration (--config.file=%q)", filename)
+	}
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	t.SetLastGood(conf)
+	logger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
+	return nil
+}
