+}
+
+func newTransactionalReloadTracker(storagePath string) *transactionalReloadTracker {
+	t := &transactionalReloadTracker{
+		path: filepath.Join(storagePath, reloadStatusFilename),
+		status: emptyReloadStatus(),
+	}
+	data, err := os.ReadFile(t.path)
+	if err != nil {
+		return t
+	}
+	var status api_v1.ReloadStatus
+	if json.Unmarshal(data, &status) == nil {
+		status.normalize()
+		t.status = status
+	}
+	return t
+}
+
+func emptyReloadStatus() api_v1.ReloadStatus {
+	return api_v1.ReloadStatus{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}
+}
+
+func (s *api_v1.ReloadStatus) normalize() {
+	if s.ErrorCategory == "" {
+		s.ErrorCategory = "none"
+	}
+	if s.AppliedReloaders == nil {
+		s.AppliedReloaders = []string{}
+	}
+	if s.ReloaderTimingsMS == nil {
+		s.ReloaderTimingsMS = map[string]int64{}
+	}
+}
+
+func (t *transactionalReloadTracker) Status() api_v1.ReloadStatus {
+	t.mu.RLock()
+	defer t.mu.RUnlock()
+	status := t.status
+	status.AppliedReloaders = append([]string(nil), status.AppliedReloaders...)
+	status.ReloaderTimingsMS = make(map[string]int64, len(status.ReloaderTimingsMS))
+	for name, duration := range status.ReloaderTimingsMS {
+		status.ReloaderTimingsMS[name] = duration
+	}
+	return status
+}
+
+func (t *transactionalReloadTracker) SetLastGood(conf *config.Config) {
+	t.mu.Lock()
+	defer t.mu.Unlock()
+	t.lastGood = conf
+}
+
+func (t *transactionalReloadTracker) record(status api_v1.ReloadStatus) {
+	status.normalize()
+	t.mu.Lock()
+	t.status = status
+	data, err := json.Marshal(status)
+	if err == nil {
+		tmp := t.path + ".tmp"
+		if os.WriteFile(tmp, data, 0o644) == nil {
+			_ = os.Rename(tmp, t.path)
+		}
+	}
+	t.mu.Unlock()
+}
+
+func (t *transactionalReloadTracker) Reload(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) error {
+	status := emptyReloadStatus()
+	status.LastReloadID = time.Now().UTC().Format(time.RFC3339)
+
+	conf, err := loadReloadConfig(filename, enableExemplarStorage, logger)
+	if err != nil {
+		status.ErrorCategory = "load_error"
+		status.ErrorMessage = err.Error()
+		t.record(status)
+		configSuccess.Set(0)
+		callback(false)
+		return err
+	}
+
+	for _, rl := range rls {
+		started := time.Now()
+		err := rl.reloader(conf)
+		status.ReloaderTimingsMS[rl.name] = durationToInt64Millis(time.Since(started))
+		if err == nil {
+			status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
+			continue
+		}
+
+		status.ErrorCategory = "apply_error"
+		status.ErrorMessage = err.Error()
+		status.FailedReloader = rl.name
+		if len(status.AppliedReloaders) > 0 {
+			status.RollbackAttempted = true
+			t.mu.RLock()
+			lastGood := t.lastGood
+			t.mu.RUnlock()
+			if lastGood != nil {
+				rollbackErr := applyReloaders(lastGood, rls)
+				status.RollbackSuccessful = rollbackErr == nil
+				if rollbackErr != nil {
+					status.ErrorCategory = "rollback_error"
+					status.ErrorMessage = fmt.Sprintf("apply failed: %v; rollback failed: %v", err, rollbackErr)
+				}
+			}
+		}
+		t.record(status)
+		configSuccess.Set(0)
+		callback(false)
+		return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, err)
+	}
+
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	t.SetLastGood(conf)
+	status.LastReloadSuccessful = true
+	t.record(status)
+	configSuccess.Set(1)
+	configSuccessTime.SetToCurrentTime()
+	callback(true)
+	return nil
+}
+
+func applyReloaders(conf *config.Config, rls []reloader) error {
+	for _, rl := range rls {
+		if err := rl.reloader(conf); err != nil {
+			return fmt.Errorf("%s: %w", rl.name, err)
+		}
+	}
+	return nil
+}
+
