func TestTransactionalReloadRollsBackAndPersistsOutcome(t *testing.T) {
	dir := t.TempDir()
	configFile := filepath.Join(dir, "prometheus.yml")
	require.NoError(t, os.WriteFile(configFile, []byte("global:\n  scrape_interval: 1m\n"), 0o644))

	tracker := newTransactionalReloadTracker(dir)
	oldConfig, err := loadReloadConfig(configFile, false, promslog.NewNopLogger())
	require.NoError(t, err)
	tracker.SetLastGood(oldConfig)
	require.NoError(t, os.WriteFile(configFile, []byte("global:\n  scrape_interval: 2m\n"), 0o644))

	applied := ""
	reloaders := []reloader{
		{name: "first", reloader: func(cfg *config.Config) error {
			applied = cfg.GlobalConfig.ScrapeInterval.String()
			return nil
		}},
		{name: "second", reloader: func(cfg *config.Config) error {
			if time.Duration(cfg.GlobalConfig.ScrapeInterval) == 2*time.Minute {
				return errors.New("apply failed")
			}
			return nil
		}},
	}

	err = tracker.Reload(configFile, false, promslog.NewNopLogger(), &safePromQLNoStepSubqueryInterval{}, func(bool) {}, reloaders...)
	require.Error(t, err)
	status := tracker.Status()
	require.False(t, status.LastReloadSuccessful)
	require.Equal(t, "apply_error", status.ErrorCategory)
	require.Equal(t, []string{"first"}, status.AppliedReloaders)
	require.True(t, status.RollbackAttempted)
	require.True(t, status.RollbackSuccessful)
	require.Equal(t, "second", status.FailedReloader)
	require.Equal(t, "1m", applied)
	require.FileExists(t, filepath.Join(dir, reloadStatusFilename))

